const Q_ECONOMICS_1989=[{"id": "objective>Economics>1989>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In its simplified form, the circular flow of income concept refers to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Real flow in goods and services between the product and factor markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monetary payments for goods and services produced by individual firms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transactions in goods and services and payments for such transactions between individual firms and households</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Money flows associated with transactions between individual firms and households</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The circular flow of income concept illustrates the transactions in goods and services and the payments for such transactions between individual firms and households. This model shows how money moves through the economy, highlighting the interdependence between different sectors.</div>", "topic": "CIRCULAR FLOW OF INCOME"}, {"id": "objective>Economics>1989>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The need to construct a scale of preference is necessitated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The need to satisfy wants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scarcity and the need for choice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scarcity of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Non-availability of factors of production</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The need to construct a scale of preference arises from scarcity and the need for choice. Scarcity means that resources are limited, and individuals must prioritize their wants and needs, leading to the creation of a scale of preference to make informed decisions.</div>", "topic": "BASIC CONCEPTS OF ECONOMICS"}, {"id": "objective>Economics>1989>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A shift in the production possibility frontier could result from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> changes in the combination of goods produced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">changes in production techniques</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A shift in the production possibility frontier (PPF) occurs when there is a change in the capacity of an economy to produce goods and services. This can happen due to changes in production techniques, which can lead to more efficient use of resources or the introduction of new technologies. For example, if a new technology allows for more efficient production of goods, the economy can produce more of both goods represented on the PPF, resulting in an outward shift of the frontier. The other options do not cause a shift in the PPF: changes in the combination of goods produced represent movement along the curve, unemployment indicates underutilization of resources without changing the economy's capacity, and inflation is a general rise in prices that does not affect production capacity.</div>", "topic": "PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>1989>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary problem of economics is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To obtain a more equitable distribution of money income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Producing a given output with the lowest cost combination of factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adoption of capital-intensive technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increasing the quantity of fixed factor of production</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary problem of economics is to produce a given output with the lowest cost combination of factors of production. This reflects the fundamental economic challenge of resource allocation and efficiency in production, aiming to maximize output while minimizing costs.</div>", "topic": "BASIC ECONOMIC PROBLEMS"}, {"id": "objective>Economics>1989>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Efficiency in production involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reducing the size of the work force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Producing a given output with the lowest cost combination of factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adopting the quantity of the fixed factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increasing the quantity of the fixed factor of production</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Efficiency in production is defined as producing a given output with the lowest cost combination of factors of production. This concept emphasizes the importance of optimizing resource use to achieve maximum productivity at minimal costs.</div>", "topic": "BASIC ECONOMIC PROBLEMS"}, {"id": "objective>Economics>1989>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If X represents the factors of production and Y represents the factor price, which of the following sets of association is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">(Land, rent), (capital, wage), (labour, profit)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(Land, interest), (capital, profits), (labour , wage)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(Land, wage), (capital, interest), (Labour, rent)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">(Land, rent), (capital, interest), (labour, wage)</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct associations of factors of production and their corresponding factor prices are (Land, rent), (capital, interest), and (labour, wage). This reflects the economic principle that land is compensated with rent, capital with interest, and labor with wages.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : RENT & INTEREST"}, {"id": "objective>Economics>1989>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the cost of production for a firm continues to increase as its output rises, the firm is said to be experiencing</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Large-scale production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Profit maximization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diseconomies of scale</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the cost of production increases as output rises, the firm is experiencing 'Diseconomies of scale'. This occurs when a company grows so large that the costs per unit increase. This can happen due to factors such as management inefficiencies, communication problems, or overuse of resources.</div>", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION"}, {"id": "objective>Economics>1989>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given perfect competition in the capital market, the opportunity cost of capital is adequately reflected by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Interest rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Returns on capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alternative capital forgone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shadow price of foreign exchange</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a perfectly competitive capital market, the opportunity cost of capital is reflected by the 'Interest rate'. This is because the interest rate represents the return that could be earned on an investment in the next best alternative, thus serving as a benchmark for the opportunity cost of capital.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1989>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If at 10k per kg, 1000kg of yam were purchased and at 5k per kg, 1500kg were purchased, the resultant point elasticity of demand is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.33</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.0001</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To calculate the point elasticity of demand, we use the formula: (ΔQ / ΔP) X  (P / Q). Here, ΔQ is the change in quantity, Q is the average quantity, ΔP is the change in price, and P is the average price.  <br/> ΔQ= 1500 - 1000 <br/> = 500 <br/>  <br/> ΔP= 5 - 10 <br/> = -5 <br/>  <br/> = 500/-5 x 10/1000 <br/>  <br/> = -1 <br/>  <br/> Since PED is always positive, the PED = 1 <br/> </div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1989>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If, as the price of a commodity rises, the quantity demanded of the commodity remains the same, then the demand for the commodity is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Static</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Infinitely elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Externally determined</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Perfectly inelastic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the price of a commodity rises and the quantity demanded remains the same, the demand for that commodity is termed 'Perfectly inelastic'. This means that consumers will purchase the same amount regardless of price changes, often seen in essential goods where no substitutes are available.</div>", "topic": "THEORY OF DEMAND : TYPES OF DEMAND"}, {"id": "objective>Economics>1989>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, what happens when the minimum wage is fixed at OW?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Unemployment is reduced</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unemployment results</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The demand schedule will shift</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The supply schedule will become steeper</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a minimum wage is fixed above the equilibrium wage (OW), it can lead to 'Unemployment results'. This is because employers may not be willing to hire as many workers at the higher wage, leading to a surplus of labor, or unemployment, as the quantity of labor supplied exceeds the quantity demanded.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1989>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> If the curve above shows the relationship between the price of commodity X and the quantity demanded for commodity Y, then X and Y are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Complementary goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inferior goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Luxury goods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The graph shows a positive relationship between the price of commodity X and the quantity demanded of commodity Y — meaning as the price of X increases, the demand for Y also increases. <br/>  <br/> This type of relationship typically indicates that the two goods are Substitutes <br/>  <br/> When the price of commodity X increases, consumers switch to commodity Y, increasing its demand. <br/>  <br/> This is a characteristic of substitute goods — products that can replace each other (e.g., margarine and butter, tea and coffee).</div>", "topic": "THEORY OF DEMAND : TYPES OF DEMAND"}, {"id": "objective>Economics>1989>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors is an important determinant of the magnitude of price elasticity of demand?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The production period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cost of storage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Durability of the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Availability of factors of production</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The durability of a product significantly affects the price elasticity of demand. Durable goods tend to have a lower price elasticity because consumers are less likely to purchase them frequently, while non-durable goods are purchased more often and tend to have higher elasticity. Therefore, the durability of the product is a key determinant of how sensitive the demand is to price changes.</div>", "topic": "THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1989>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal theory of distribution makes an assertion that the price of any factor depends up its marginal</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Productivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rate of substitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Revenue</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal theory of distribution states that the price of any factor of production is determined by its marginal productivity. This means that the value of a factor is based on the additional output that is produced by employing one more unit of that factor, which is referred to as its marginal productivity.</div>", "topic": "BASIC CONCEPTS OF ECONOMICS"}, {"id": "objective>Economics>1989>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to increase its profit margin, the monopolist can manipulate</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Both price and output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Either price or output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Only it price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Only it output</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the monopolist chooses the output level, the price is determined by the demand curve. <br/>  <br/> If the monopolist sets a price, the quantity demanded (and hence output) is determined by how consumers respond. <br/>  <br/> So, the monopolist can choose either the price or the output, but not both independently.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY"}, {"id": "objective>Economics>1989>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a purely competitive industry, a fundamental requirement of the demand curve faced by individual firms is that it should be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Downward sloping and price inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Perfectly price elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Downward sloping but price inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Perfectly price inelastic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a purely competitive industry, the demand curve faced by individual firms is perfectly price elastic. This means that firms are price takers and can sell any quantity of their product at the market price, but cannot influence the price themselves. If they try to charge more than the market price, they will sell nothing, as consumers can buy from other firms at the market price.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>1989>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The merging of firms engaged in different stages of production and marketing is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">External economies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vertical integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Horizontal integration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economic union</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The merging of firms engaged in different stages of production and marketing is called 'Vertical integration'. This concept refers to a company's expansion into different stages of production within the same industry, allowing for greater control over the supply chain and potentially reducing costs.</div>", "topic": "BUSINESS ORGANISATION : PARTNERSHIP"}, {"id": "objective>Economics>1989>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an important function of the retailer?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Grants credit to the wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Breaks bulk and sells products in small units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduce cost of distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Generates demand for products through advertisement</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An important function of the retailer is to 'Breaks bulk and sells products in small units'. Retailers purchase large quantities of goods from wholesalers and sell them in smaller quantities to consumers, making products more accessible.</div>", "topic": "DISTRIBUTIVE TRADE : THE RETAILER"}, {"id": "objective>Economics>1989>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Q(ton)</td><td style=\"border:1px solid black;text-align:center;\"> 400</td><td style=\"border:1px solid black;text-align:center;\"> 500</td><td style=\"border:1px solid black;text-align:center;\"> 600</td><td style=\"border:1px solid black;text-align:center;\"> 700</td><td style=\"border:1px solid black;text-align:center;\"> 800</td><td style=\"border:1px solid black;text-align:center;\"> 900</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">TC(N)</td><td style=\"border:1px solid black;text-align:center;\"> 16000</td><td style=\"border:1px solid black;text-align:center;\"> 180000</td><td style=\"border:1px solid black;text-align:center;\"> 21000</td><td style=\"border:1px solid black;text-align:center;\"> 24000</td><td style=\"border:1px solid black;text-align:center;\"> 31500</td><td style=\"border:1px solid black;text-align:center;\"> 40000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">TR(N)</td><td style=\"border:1px solid black;text-align:center;\">22000</td><td style=\"border:1px solid black;text-align:center;\">22500</td><td style=\"border:1px solid black;text-align:center;\">24500</td><td style=\"border:1px solid black;text-align:center;\">24500</td><td style=\"border:1px solid black;text-align:center;\">18000</td><td style=\"border:1px solid black;text-align:center;\">15000</td></tr></table></div> <br/>  <br/> The table above gives the various levels of output (Q) and its corresponding total cost (TC) and total revenue (TR) for a firm. <br/>  <br/> Which output level Q results in maximum profit? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">700</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the output level that results in maximum profit, we calculate Profit = Total Revenue (TR) – Total Cost (TC) for each quantity. <br/> <img src=\"1989/N9G8YN.png\" style=\"position:relative;max-width:100%;\"/> <br/> Maximum profit is ₦6,000 at Q = 400 tons</div>", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION"}, {"id": "objective>Economics>1989>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the purpose of advertisement in marketing is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Change the quality of the product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Raise the quantity of the product demanded as its price falls</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shifts the demand curve for the product to the right</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Raise production costs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the purposes of advertisement in marketing is to 'Shifts the demand curve for the product to the right'. Advertising increases consumer awareness and interest in a product, leading to an increase in demand at all price levels.</div>", "topic": "DISTRIBUTIVE TRADE : INTRODUCTION"}, {"id": "objective>Economics>1989>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The size of a business unit tends to be small if the activity</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Involves mass production of goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Requires a large capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Requires division of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Involves the provision of direct services</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The size of a business unit tends to be small if the activity 'Involves the provision of direct services'. Service-oriented businesses often require a more personalized approach, which typically leads to smaller operational scales compared to mass production.</div>", "topic": "BUSINESS ORGANISATION : SOLE PROPRIETOSHIP"}, {"id": "objective>Economics>1989>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which type of business organization has the attribute of effectively combining management with control?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sole proprietorship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Partnership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Limited liability company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Co-operatives</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Limited Liability Company (LLC) effectively combines management with control because it allows owners (members) to manage the business while also providing limited liability protection. This means that the personal assets of the members are protected from business debts and liabilities, which is a key feature that distinguishes LLCs from sole proprietorships and partnerships.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>1989>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The co-operatives as a form of business organization differs from partnership by having</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Several sources of capital for business financing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ability to issue preferred stocks to members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Entrenched democratic control in the conduct of business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Established rules and regulations governing</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Co-operatives differ from partnerships primarily in their democratic control structure. In a co-operative, each member typically has one vote regardless of their investment, promoting equal participation in decision-making. This entrenched democratic control is a fundamental characteristic of co-operatives, setting them apart from partnerships where control is usually proportional to ownership.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>1989>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of business finance that entitles the holder to a fixed rate of dividend is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Preferred stock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Common stock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debenture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bank loan</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Preferred stock is a type of business finance that entitles the holder to a fixed rate of dividend. Unlike common stock, which may pay dividends at varying rates depending on the company's performance, preferred stockholders receive dividends at a predetermined rate, making it a more stable investment.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>1989>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the business organizations listed below is characterized by limited authority and liability of the individual owners?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sole proprietorship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Partnership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Joint stock company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Co-operative society</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Joint Stock Company is characterized by limited authority and liability of the individual owners (shareholders). In this structure, shareholders are only liable for the company's debts up to the amount they invested, which protects their personal assets. This limited liability is a significant advantage of joint stock companies compared to sole proprietorships and partnerships.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>1989>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A company is said to be highly geared if the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Value of fixed interest loans is high compared with share capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Value of share capital is high compared with fixed interest loans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dividend rate is high</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interest rate is high</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A company is said to be highly geared if the value of fixed interest loans (debt) is high compared with share capital (equity). High gearing indicates that a company relies heavily on debt financing, which can increase financial risk but also the potential for higher returns on equity if the company performs well.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>1989>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industries that can be randomly located are characterized by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Relatively low transport cost for both raw materials and output and factor mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Relatively heavy transport cost of raw material or output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Costant returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Significant economy of scale</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Industries that can be randomly located are typically characterized by relatively low transport costs for both raw materials and outputs, as well as factor mobility. This means that the location of the industry is not heavily dependent on the proximity to resources or markets, allowing for flexibility in choosing locations.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>1989>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term \" double coincidence\" of wants is usually associated with a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bilateral exchange system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monetary exchange system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stock exchange system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Barter exchange system</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term 'double coincidence of wants' is associated with a barter exchange system. In barter, each party must have what the other wants, which is the essence of the double coincidence of wants. This is a limitation of barter that does not exist in monetary systems.</div>", "topic": "THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1989>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major factor affecting the value of money is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Banking habit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transaction motive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Divisible nature of money</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major factor affecting the value of money is the price level. The value of money is inversely related to the price level; as prices rise, the purchasing power of money falls, thus affecting its value.</div>", "topic": "MONEY : VALUE OF MONEY"}, {"id": "objective>Economics>1989>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cost push inflation is caused by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Growth of government expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in factor prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in money supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hoarding</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost-push inflation is caused by an increase in factor prices, such as wages and raw materials. When the costs of production rise, producers may pass these costs onto consumers in the form of higher prices, leading to inflation.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>1989>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stock exchange market is where</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Businessmen borrow some capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The federal government trades on treasury bills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Existing bonds and stocks are traded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">New stocks and shares are bought or sold</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The stock exchange market is where existing bonds and stocks are traded. It is a platform for buying and selling securities that have already been issued, as opposed to new stocks and shares which are typically sold in an initial public offering (IPO).</div>", "topic": "FINANCIAL INSTITUTION : STOCK EXCHANGE"}, {"id": "objective>Economics>1989>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial bank reserves at the Central Bank have the effect of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Controlling credit and money supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Discouraging banking operations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Advancing trade prospects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reducing bank frauds</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial bank reserves at the Central Bank are crucial for controlling the credit and money supply in the economy. By adjusting the reserve requirements, the Central Bank can influence how much money banks can lend, thereby controlling inflation and stabilizing the economy.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>1989>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tax is defined as regressive if </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The proportion of income paid as tax increase as the income level increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All income groups pay the same percentage as their income as taxes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The proportion of income taken by the tax falls as income increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The proportion of income taken by the tax is a fixed nominal amount of income for all income groups</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A regressive tax is one where the proportion of income paid as tax decreases as income increases. This means that lower-income individuals pay a higher percentage of their income in taxes compared to higher-income individuals, which is contrary to a progressive tax system.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>1989>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government intervention in an economy is often justified on the ground that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wants are unlimited while resources are scarce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Productivity is higher in the public than in the private sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Free market may not work or produce desire results</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost of government expenditure is zero</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Government intervention is often justified because free markets may not always produce desirable results, such as equity or efficiency. Market failures, such as monopolies or externalities, can necessitate government action to correct these inefficiencies.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>1989>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The three major groups of government revenue are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Investment income, direct tax and export duties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Import duties, excise tax and export duties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Company tax, personal income tax and import duties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Company tax, import duties and excise duties</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The three major groups of government revenue typically include company tax, import duties, and excise duties. These sources represent significant ways in which governments collect revenue to fund public services and infrastructure.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>1989>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main objectives of public expenditure does NOT include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Stabilization of national economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Achievement of a more equitable income distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Meeting the social heeds of the people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Revenue sharing and profit maximization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main objectives of public expenditure do not include revenue sharing and profit maximization. Instead, public expenditure aims to stabilize the economy, achieve equitable income distribution, and meet social needs, which are fundamentally different from profit-oriented goals.</div>", "topic": "PUBLIC FINANCE : INTRODUCTION"}, {"id": "objective>Economics>1989>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A perfect example of a public good is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Defence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transport</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A public good has two main characteristics: <br/> - Non-excludability – You can't stop people from benefiting from it. <br/> - Non-rivalry – One person's use doesn't reduce availability for others. <br/>  <br/> Air – While it seems public, it can be polluted, and clean air isn't always equally available (so not always non-rival). <br/>  <br/> Education – This is not a pure public good; it is excludable (you can charge fees) and rivalrous (limited space). <br/>  <br/> Transport – It is excludable (tickets/fare) and rivalrous (traffic/congestion), so not a public good.</div>", "topic": "PUBLIC FINANCE : INTRODUCTION"}, {"id": "objective>Economics>1989>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A balanced budget is defined as a condition of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Balance of payments equilibrium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equality of aggregate demand and aggregate supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equality of planned receipts and planned expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equality of planned exports and planned imports</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A balanced budget is defined as a condition where there is equality of planned receipts and planned expenditure. This means that the total income (receipts) matches the total spending (expenditure), resulting in no deficit or surplus.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>1989>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">ITEM</td><td style=\"border:1px solid black;text-align:center;\"> AMOUNT (Million Naira)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Visible exports</td><td style=\"border:1px solid black;text-align:center;\"> 55.54</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Visible imports</td><td style=\"border:1px solid black;text-align:center;\"> 53. 32</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Invisible exports</td><td style=\"border:1px solid black;text-align:center;\"> 30.56</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Invisible imports</td><td style=\"border:1px solid black;text-align:center;\"> 28.70</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Balance</td><td style=\"border:1px solid black;text-align:center;\">4.08</td></tr></table></div> <br/>  <br/> The amount, #4.08, shown as balance in the table above represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Terms of payments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Balance on current account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Balance of trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Terms of trade</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amount #4.08 shown as balance in the table represents the balance on the current account. The current account includes visible trade (exports and imports of goods) and invisible trade (services, income, and current transfers). The balance on the current account is the net of these transactions.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>1989>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">By using exchange controls, a country tries to eliminate a balance of payments deficit by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Limited her imports to its currency value of exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reducing the nations domestic price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Limiting her exports to its currency value of imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Overvaluing the country's currency</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">By using exchange controls, a country tries to eliminate a balance of payments deficit by limiting her imports to its currency value of exports. This means that the country restricts the amount of foreign currency available for imports to ensure that it does not exceed the value of its exports, thus helping to balance the payments.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>1989>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The law of comparative advantage states that a country should specialize in the production of  a commodity</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">For which local demand is greatest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">In which its opportunity cost is lower than that of the trade partner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">For which foreign demand is greatest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">For which there is abundant supply of raw materials</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of comparative advantage states that a country should specialize in the production of a commodity in which its opportunity cost is lower than that of the trade partner. This means that a country can produce certain goods more efficiently than others, allowing for more effective trade and resource allocation.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>1989>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">International and inter-regional trade differ primarily because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">comparative advantage is relevant to the former but not the latter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">products flow across national boundaries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there are different resources supplies among countries of the world</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the regulation from GATT</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">International trade involves the exchange of goods and services across national borders, which is influenced by the different resources available in each country. This is why the correct answer is that there are different resource supplies among countries of the world.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>1989>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Optimum population is the population level at which</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Death rate is at a minimum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Per capita income is at maximum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population is at a maximum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Death rate is equal to birth rate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Optimum population refers to the ideal population size that maximizes per capita income. This means that resources are utilized efficiently, leading to the highest possible income per person. Therefore, the correct answer is that per capita income is at maximum.</div>", "topic": "POPULATION : INTRODUCTION"}, {"id": "objective>Economics>1989>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The group of people engaged in banking or insurance services by occupational distributions are classified as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Primary producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Secondary producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tertiary producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Technical producers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The group of people engaged in banking or insurance services is classified as tertiary producers. Tertiary production involves services rather than goods, which is characteristic of banking and insurance sectors.</div>", "topic": "FINANCIAL INSTITUTION : INTRODUCTION"}, {"id": "objective>Economics>1989>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between gross national product and net national product is equal to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gross investment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Net investment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Net foreign income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital depreciation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between gross national product (GNP) and net national product (NNP) is equal to capital depreciation. GNP measures the total economic output, while NNP accounts for the loss of value of capital goods over time, which is represented by depreciation.</div>", "topic": "NATIONAL INCOME : DIFFERENCE BETWEEN STANDARD OF LIVING & COST OF LIVING"}, {"id": "objective>Economics>1989>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The value of the total output produced within Nigeria by all residents (citizens and non-citizens) is referred to as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gross national product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Disposable income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gross domestic product</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The value of the total output produced within Nigeria by all residents, regardless of citizenship, is referred to as Gross Domestic Product (GDP). GDP measures the economic performance of a country based on the location of production.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>1989>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The multiplier is defined as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The ratio of the change in income to the change in investment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The change in investment divided by the change in income</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />(1-MPS)</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />(MPC)</td></tr></table></div></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The multiplier is defined as the ratio of the change in income to the change in investment. This concept is fundamental in Keynesian economics, where it illustrates how an initial change in spending (investment) can lead to a larger change in overall income. The multiplier effect occurs because one person's spending becomes another person's income, leading to further spending and income generation.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>1989>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If C stands for consumption expenditure, I for investment, X for exports, and M for imports, then national income is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C + I + X  + M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C + I + X - M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C + I - X + M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C + I + X</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">National income is calculated as C + I + X - M, where C is consumption, I is investment, X is exports, and M is imports. This formula reflects the total economic activity within a country, accounting for the goods and services produced domestically (C + I + X) and subtracting the value of imports (M) that are not produced within the country.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>1989>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sustained increase in the per capita income of a country over a period of time is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Economic growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economic development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Structural change</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stagflation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A sustained increase in per capita income over time is referred to as economic growth. This term indicates an improvement in the economic performance of a country, typically measured by the increase in the production of goods and services per person. Economic development, while related, encompasses broader improvements in living standards and quality of life.</div>", "topic": "ECONOMIC GROWTH AND DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>1989>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary goal of development planning in Nigeria is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase profitability of enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Achieve a rapid increase in the welfare and standard of living of Nigerians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase the level of gross domestic product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Make Nigeria a super-power</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary goal of development planning in Nigeria is to achieve a rapid increase in the welfare and standard of living of Nigerians. This goal focuses on improving the quality of life for the population through various means, including economic growth, social services, and infrastructure development, rather than solely increasing GDP or profitability.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}];
